// ---------------------------------------------------------------------------
// Imports
// ---------------------------------------------------------------------------

import 'dart:typed_data';

import 'key_cache_entry.dart';

// ---------------------------------------------------------------------------
// Key Cache
// ---------------------------------------------------------------------------

abstract class CamoKeyCache {
  // ---------------------------------------------------------------------------
  // Get
  // ---------------------------------------------------------------------------

  KeyCacheEntry? get(
    String pairId,
  );

  // ---------------------------------------------------------------------------
  // Put
  // ---------------------------------------------------------------------------

  void put({
    required String pairId,
    required Uint8List key,
  });

  // ---------------------------------------------------------------------------
  // Remove
  // ---------------------------------------------------------------------------

  void remove(
    String pairId,
  );

  // ---------------------------------------------------------------------------
  // Clear
  // ---------------------------------------------------------------------------

  void clear();
}